import type { MacroRiskOverlay } from '../../macro-risk-overlay';
import type { ReplayAdaptationSnapshot } from '../../replay-adaptation';
import { getReplayThemeProfileFromSnapshot, getCurrentThemePerformanceFromSnapshot } from '../../replay-adaptation';
import { computeThemeStabilityAdjustment } from '../portfolio-optimizer';
import { predictHitProbability } from '../adaptive-params/weight-learner.js';
import type { MetaWeights } from '../adaptive-params/weight-learner.js';

import type {
  IdeaGenerationRuntimeContext,
  InvestmentIdeaCard,
} from '../types';
import { clamp } from '../utils';
import {
  getThemeRule,
  resolveThemePolicy,
} from '../theme-registry';

// ============================================================================
// META WEIGHTS LOADING
// ============================================================================

type MetaWeightsLoadStatus = 'ready' | 'missing' | 'invalid' | 'unsupported';

export interface MetaWeightsLoadState {
  status: MetaWeightsLoadStatus;
  weights: MetaWeights | null;
  path: string | null;
  error: string | null;
}

function isNodeRuntime(): boolean {
  return typeof process !== 'undefined' && Boolean(process.versions?.node);
}

function isMetaWeights(weights: unknown): weights is MetaWeights {
  if (!weights || typeof weights !== 'object') return false;
  const candidate = weights as MetaWeights;
  return Array.isArray(candidate.featureNames)
    && candidate.featureNames.length === 11
    && Array.isArray(candidate.weights)
    && candidate.weights.length === 11
    && candidate.featureNames.includes('confidence')
    && candidate.featureNames.includes('driftPenalty');
}

function buildMetaWeightsLoadState(): MetaWeightsLoadState {
  if (!isNodeRuntime()) {
    return {
      status: 'unsupported',
      weights: null,
      path: null,
      error: 'Meta weights loading is only available in a Node-capable runtime.',
    };
  }

  const configuredPath = String(
    process.env.WM_META_WEIGHTS_PATH
    || process.env.LEARNED_META_WEIGHTS_PATH
    || 'data/learned_meta_weights.json',
  ).trim();

  try {
    const nodeRequire = (new Function(
      'return typeof require === "function" ? require : null;',
    )() as ((specifier: string) => {
      resolveWeightsPath: (inputPath: string) => string;
      loadWeightsSync: (pathLike: string) => unknown;
    }) | null);

    if (!nodeRequire) {
      return {
        status: 'unsupported',
        weights: null,
        path: configuredPath,
        error: 'Meta weights loading requires Node require().',
      };
    }

    let nodeLoader:
      | {
        resolveWeightsPath: (inputPath: string) => string;
        loadWeightsSync: (pathLike: string) => unknown;
      }
      | null = null;
    let lastError: unknown = null;
    for (const specifier of [
      './adaptive-params/weight-learner.node.js',
      './adaptive-params/weight-learner.node.ts',
    ]) {
      try {
        nodeLoader = nodeRequire(specifier);
        break;
      } catch (error) {
        lastError = error;
      }
    }

    if (!nodeLoader) {
      throw lastError instanceof Error
        ? lastError
        : new Error('Unable to load node weight loader.');
    }

    const resolvedPath = nodeLoader.resolveWeightsPath(configuredPath);
    const loaded = nodeLoader.loadWeightsSync(resolvedPath);
    if (!isMetaWeights(loaded)) {
      return {
        status: 'invalid',
        weights: null,
        path: resolvedPath,
        error: `Unexpected meta weight shape at ${resolvedPath}.`,
      };
    }

    return {
      status: 'ready',
      weights: loaded,
      path: resolvedPath,
      error: null,
    };
  } catch (error) {
    const message = String(error instanceof Error ? error.message : error);
    return {
      status: /ENOENT|no such file/i.test(message) ? 'missing' : 'invalid',
      weights: null,
      path: configuredPath,
      error: message,
    };
  }
}

const metaWeightsState = buildMetaWeightsLoadState();

export function getMetaWeightsLoadState(): MetaWeightsLoadState {
  return {
    status: metaWeightsState.status,
    weights: metaWeightsState.weights
      ? {
        featureNames: [...metaWeightsState.weights.featureNames],
        weights: [...metaWeightsState.weights.weights],
        bias: metaWeightsState.weights.bias,
      }
      : null,
    path: metaWeightsState.path,
    error: metaWeightsState.error,
  };
}

// ============================================================================
// META TRADE ADMISSION
// ============================================================================

export function applyMetaTradeAdmission(
  card: InvestmentIdeaCard,
  macroOverlay: MacroRiskOverlay,
  replayAdaptation: ReplayAdaptationSnapshot | null,
  runtimeContext: IdeaGenerationRuntimeContext,
): InvestmentIdeaCard {
  const theme = getThemeRule(card.themeId);
  const themePolicy = theme ? resolveThemePolicy(theme) : null;
  const replayProfile = getReplayThemeProfileFromSnapshot(replayAdaptation, card.themeId);
  const currentPerformance = getCurrentThemePerformanceFromSnapshot(replayAdaptation, card.themeId);
  const stability = computeThemeStabilityAdjustment(card.themeId);
  const narrativePenalty = Number(
    themePolicy?.narrative.enabled
      ? card.narrativeShadowState === 'mismatch'
        ? themePolicy.narrative.mismatchPenalty
        : card.narrativeShadowState === 'weak'
          ? themePolicy.narrative.weakPenalty
          : 0
      : 0,
  ) || 0;
  const symbolRules = card.symbols
    .map((symbol) => themePolicy?.symbolAdjustments[String(symbol.symbol || '').trim().toUpperCase()])
    .filter((value): value is NonNullable<typeof value> => Boolean(value));
  const specialSymbolPenalty = symbolRules.reduce((sum, rule) => sum + (rule.metaScorePenalty || 0), 0);
  const specialSizeMultiplier = symbolRules.length > 0
    ? Math.min(...symbolRules.map((rule) => rule.sizeMultiplier ?? 1))
    : 1;
  const specialWeightBlock = symbolRules.some((rule) => rule.requireRiskOff) && !macroOverlay.killSwitch && macroOverlay.state === 'risk-on';
  const hedgeHeavyPenalty =
    themePolicy?.classification === 'hedge-heavy'
      ? macroOverlay.state === 'risk-on'
        ? 0.08
        : macroOverlay.state === 'balanced'
          ? 0.03
          : 0
      : 0;

  const replayHitRate = clamp(Number(replayProfile?.hitRate ?? card.backtestHitRate ?? 50), 0, 100);
  const replayReturnPct = Number(replayProfile?.costAdjustedAvgReturnPct ?? card.backtestAvgReturnPct ?? 0) || 0;
  const currentHitRate = clamp(Number(currentPerformance?.hitRate ?? replayHitRate), 0, 100);
  const currentReturnPct = Number(currentPerformance?.avgReturnPct ?? replayReturnPct) || 0;
  const driftPenalty = clamp(Math.abs(Math.min(0, Number(replayProfile?.currentVsReplayDrift ?? 0))) / 2.5, 0, 1);
  const confidence = clamp(card.calibratedConfidence / 100, 0, 1);
  const confirmation = clamp(card.confirmationScore / 100, 0, 1);
  const reality = clamp(card.realityScore / 100, 0, 1);
  const coverage = clamp(1 - card.coveragePenalty / 120, 0, 1);
  const bandit = clamp((Number(card.banditScore) || 50) / 100, 0, 1);
  const transfer = clamp(Number(card.transferEntropy) || 0, 0, 1);
  const clusterConfidence = clamp((Number(card.clusterConfidence) || 0) / 100, 0, 1);
  const gp = runtimeContext.signal.transmissionProxy;
  const marketStressPrior = clamp(Number(card.marketStressPrior) || (gp?.marketStress ?? 0), 0, 1);
  const transmissionStress = clamp(Number(card.transmissionStress ?? card.marketStressPrior ?? 0) || (gp?.transmissionStrength ?? 0), 0, 1);
  const evidenceSupport = clamp(
    clusterConfidence * 0.58
    + marketStressPrior * 0.24
    + transmissionStress * 0.18,
    0,
    1,
  );
  const falsePositivePenalty = clamp(card.falsePositiveRisk / 100, 0, 1);
  const shadowPosterior = clamp((Number(card.narrativeShadowPosterior) || 0) / 100, 0, 1);
  const shadowDisagreement = clamp((Number(card.narrativeShadowDisagreement) || 0) / 100, 0, 1);
  const narrativeAlignment = clamp((Number(card.narrativeAlignmentScore) || 50) / 100, 0, 1);
  const shadowThemeAgreement = card.narrativeShadowTopThemeId
    ? String(card.narrativeShadowTopThemeId).trim().toLowerCase() === String(card.themeId).trim().toLowerCase()
      ? 1
      : 0
    : 0.5;
  const shadowSupport = clamp(
    shadowPosterior * (0.56 + shadowThemeAgreement * 0.44)
    + narrativeAlignment * 0.18
    - shadowDisagreement * 0.72,
    0,
    1,
  );
  const shadowPenalty = clamp(
    (card.narrativeShadowState === 'mismatch'
      ? 0.12
      : card.narrativeShadowState === 'weak'
        ? 0.05
        : 0)
    + shadowDisagreement * 0.08
    + (shadowThemeAgreement === 0 && shadowPosterior >= 0.58 ? 0.05 : 0),
    0,
    0.45,
  );
  const stressPenalty = macroOverlay.killSwitch
    ? 0.22
    : macroOverlay.state === 'risk-off'
      ? 0.1
      : macroOverlay.state === 'balanced'
        ? 0.04
        : 0;
  const stabilityExposure = clamp(stability.exposureMultiplier, 0, 1.2);
  let mlProbability: number | null = null;
  if (metaWeightsState.weights) {
    mlProbability = predictHitProbability(metaWeightsState.weights, {
      confidence,
      confirmation,
      reality,
      replayHitRate,
      currentHitRate,
      coverage,
      bandit,
      transfer,
      stability: stabilityExposure,
      falsePositivePenalty,
      driftPenalty,
    });
  }
  const hardcodedBaseProb = Number((
    confidence * 0.18
    + confirmation * 0.18
    + reality * 0.16
    + (replayHitRate / 100) * 0.16
    + (currentHitRate / 100) * 0.1
    + coverage * 0.08
    + bandit * 0.08
    + transfer * 0.06
    + evidenceSupport * 0.08
    + stabilityExposure * 0.06
    - falsePositivePenalty * 0.14
    - driftPenalty * 0.08
  ).toFixed(4));
  const ragConfidence = clamp(runtimeContext.rag.confidence ?? 0, 0, 1);
  const ragAdjustment = runtimeContext.rag.hitRate != null
    ? (clamp(runtimeContext.rag.hitRate, 0, 1) - 0.5) * ragConfidence * 0.12
    : 0;
  const baseProb = (mlProbability ?? hardcodedBaseProb) + ragAdjustment;
  const fallbackMetaHitProbability = clamp(
    Number((hardcodedBaseProb - stressPenalty - hedgeHeavyPenalty - shadowPenalty).toFixed(4)),
    0.03,
    0.97,
  );

  const metaHitProbability = mlProbability === null
    ? fallbackMetaHitProbability
    : clamp(baseProb - stressPenalty - hedgeHeavyPenalty - shadowPenalty, 0.03, 0.97);

  const metaExpectedReturnPct = Number((
    replayReturnPct * 0.55
    + currentReturnPct * 0.2
    + Math.max(0, card.calibratedConfidence - 55) * 0.015
    + Math.max(0, card.realityScore - 60) * 0.01
    + Math.max(0, stability.lcbUtility) * 0.18
    + clusterConfidence * 0.85
    + marketStressPrior * 0.65
    + transmissionStress * 0.45
    - card.falsePositiveRisk * 0.012
    - card.coveragePenalty * 0.01
    - driftPenalty * 0.55
    - stressPenalty * 1.8
    - narrativePenalty * 0.05
    - shadowPenalty * 1.4
  ).toFixed(3));

  const metaDecisionScore = Number((
    metaHitProbability * 100
    + metaExpectedReturnPct * 7
    + stability.stabilityScore * 0.22
    + (Number(card.narrativeAlignmentScore) || 50) * 0.08
    + evidenceSupport * 10
    - card.falsePositiveRisk * 0.28
    - card.coveragePenalty * 0.12
    - specialSymbolPenalty
    - narrativePenalty * 1.2
    - shadowPenalty * 16
  ).toFixed(2));

  // ── Continuous Conviction Score ─────────────────
  const continuousConviction = clamp(
    metaHitProbability * 45
    + Math.max(0, metaExpectedReturnPct) * 8
    + (metaDecisionScore / 100) * 35
    + evidenceSupport * 12,
    0,
    100,
  );

  const thresholdPolicy = runtimeContext.admission.thresholds ?? themePolicy?.admission;
  // Legacy threshold variables — retained for threshold-optimizer integration (Phase 2).
  void (thresholdPolicy?.rejectHitProbability ?? 0.44);
  void (thresholdPolicy?.watchHitProbability ?? 0.52);
  void (thresholdPolicy?.rejectExpectedReturnPct ?? -0.2);
  void (thresholdPolicy?.watchExpectedReturnPct ?? 0.08);
  void (thresholdPolicy?.rejectScore ?? 38);
  void (thresholdPolicy?.watchScore ?? 52);

  // admissionState derived from continuousConviction (for logging + backward compat)
  let admissionState: 'accepted' | 'watch' | 'rejected' = 'accepted';
  let autonomyAction = card.autonomyAction;

  if (specialWeightBlock || continuousConviction < 15) {
    admissionState = 'rejected';
    autonomyAction = 'abstain';
  } else if (continuousConviction < 55) {
    admissionState = 'watch';
    if (autonomyAction === 'deploy') autonomyAction = 'watch';
  }

  // Continuous sizing: sigmoid-like scaling from conviction
  // conviction 0 → ~0.02, 25 → ~0.15, 50 → ~0.50, 75 → ~0.88, 100 → ~0.98
  const convictionFraction = continuousConviction / 100;
  const metaSizeScale = continuousConviction < 10
    ? 0
    : clamp(
      0.05 + convictionFraction * convictionFraction * 1.08,
      0.05,
      1.18,
    );

  return {
    ...card,
    autonomyAction,
    admissionState,
    continuousConviction: Number(continuousConviction.toFixed(2)),
    metaHitProbability: Number((metaHitProbability * 100).toFixed(2)),
    metaExpectedReturnPct,
    metaDecisionScore,
    sizePct: Number((card.sizePct * metaSizeScale * specialSizeMultiplier).toFixed(2)),
    autonomyReasons: Array.from(new Set([
      ...card.autonomyReasons,
      `Meta gate: hit=${(metaHitProbability * 100).toFixed(1)}%, exp=${metaExpectedReturnPct.toFixed(2)}%, score=${metaDecisionScore.toFixed(1)}.`,
      `Evidence prior: cluster=${(clusterConfidence * 100).toFixed(1)}%, stressPrior=${marketStressPrior.toFixed(2)}, transmission=${transmissionStress.toFixed(2)}.`,
      specialSymbolPenalty > 0 ? `Special-symbol calibration penalty=${specialSymbolPenalty.toFixed(1)}.` : '',
      card.narrativeShadowState ? `Narrative shadow=${card.narrativeShadowState} (${Number(card.narrativeAlignmentScore || 0).toFixed(0)}), posterior=${Number(card.narrativeShadowPosterior || 0).toFixed(1)}%, disagreement=${Number(card.narrativeShadowDisagreement || 0).toFixed(1)}, support=${(shadowSupport * 100).toFixed(1)}%.` : '',
      specialWeightBlock ? 'Risk-on regime blocked a risk-off-only special symbol.' : '',
      admissionState === 'rejected'
        ? 'Selective abstention rejected this idea before capital allocation.'
        : admissionState === 'watch'
          ? 'Selective gate downgraded this idea to watch-only because expected edge is too thin.'
          : 'Selective gate accepted this idea for allocation review.',
    ])).slice(0, 6),
  };
}

import type {
  ForwardReturnRecord,
  HistoricalReplayRun,
} from './historical-intelligence';
import { getPersistentCache, setPersistentCache } from './persistent-cache';
import {
  getCoveragePenaltyForTheme,
  mergeCoverageLedgerSnapshots,
  type CoverageLedgerSnapshot,
} from './coverage-ledger';

export type ReplayWorkflowStatus = 'ready' | 'watch' | 'blocked';

export interface ReplayWorkflowStep {
  id: string;
  label: string;
  status: ReplayWorkflowStatus;
  metric: number;
  summary: string;
}

export interface ReplayThemeHorizonMetric {
  horizonHours: number;
  sampleSize: number;
  hitRate: number;
  rawAvgReturnPct: number;
  costAdjustedAvgReturnPct: number;
  avgRealityScore: number;
  avgExecutionPenaltyPct: number;
  tradableRate: number;
  uniqueSymbolCount: number;
  utilityScore: number;
}

export interface ReplayThemeRegimeProfile {
  regimeId: string;
  sampleSize: number;
  hitRate: number;
  costAdjustedAvgReturnPct: number;
  confirmationScore: number;
  utilityScore: number;
}

export interface CurrentThemePerformanceMetric {
  themeId: string;
  activeCount: number;
  closedCount: number;
  hitRate: number;
  avgReturnPct: number;
  confirmationScore: number;
  updatedAt: string;
}

export interface ReplayThemeProfile {
  themeId: string;
  preferredHorizonHours: number;
  candidateHorizonHours: number[];
  timeframe: string;
  confidence: number;
  weightedSampleSize: number;
  hitRate: number;
  rawAvgReturnPct: number;
  costAdjustedAvgReturnPct: number;
  avgRealityScore: number;
  avgExecutionPenaltyPct: number;
  tradableRate: number;
  utilityScore: number;
  regimeMetrics: ReplayThemeRegimeProfile[];
  confirmationReliability: number;
  coverageAdjustedUtility: number;
  robustUtility: number;
  windowMedianUtility: number;
  windowUtilityStd: number;
  windowFlipRate: number;
  currentVsReplayDrift: number;
  horizonMetrics: ReplayThemeHorizonMetric[];
  updatedAt: string;
}

export interface ReplayWorkflowPerformance {
  updatedAt: string;
  runCount: number;
  themeCount: number;
  uniqueSymbolCount: number;
  frameCount: number;
  evaluationFrameCount: number;
  ideaRunCount: number;
  forwardReturnCount: number;
  costAdjustedHitRate: number;
  costAdjustedAvgReturnPct: number;
  avgRealityScore: number;
  avgExecutionPenaltyPct: number;
  nonTradableRate: number;
  coverageScore: number;
  qualityScore: number;
  executionScore: number;
  activityScore: number;
}

export interface PortfolioAccountingSummary {
  source: 'run' | 'inferred' | 'aggregated' | 'missing';
  available: boolean;
  weightedReturnPct: number | null;
  navStart: number | null;
  navEnd: number | null;
  navChangePct: number | null;
  cagrPct: number | null;
  maxDrawdownPct: number | null;
  sharpe: number | null;
  annualizedVolatilityPct: number | null;
  sampleCount: number;
  tradeCount: number;
  curvePointCount: number;
}

export interface ReplayRunDigestThemeMetric {
  themeId: string;
  horizonHours: number;
  sampleSize: number;
  hitRate: number;
  rawAvgReturnPct: number;
  costAdjustedAvgReturnPct: number;
  avgRealityScore: number;
  avgExecutionPenaltyPct: number;
  tradableRate: number;
  uniqueSymbolCount: number;
}

export interface ReplayRunDigest {
  id: string;
  label: string;
  mode: 'replay' | 'walk-forward';
  completedAt: string;
  frameCount: number;
  evaluationFrameCount: number;
  ideaRunCount: number;
  forwardReturnCount: number;
  uniqueThemeCount: number;
  uniqueSymbolCount: number;
  costAdjustedHitRate: number;
  costAdjustedAvgReturnPct: number;
  avgRealityScore: number;
  avgExecutionPenaltyPct: number;
  nonTradableRate: number;
  portfolio: PortfolioAccountingSummary | null;
  themeMetrics: ReplayRunDigestThemeMetric[];
  themeRegimeMetrics?: HistoricalReplayRun['themeRegimeMetrics'];
  coverageLedger?: CoverageLedgerSnapshot | null;
}

export interface ReplayAdaptationSnapshot {
  updatedAt: string;
  recentRuns: ReplayRunDigest[];
  themeProfiles: ReplayThemeProfile[];
  currentThemePerformance: CurrentThemePerformanceMetric[];
  coverageLedger: CoverageLedgerSnapshot | null;
  workflow: ReplayWorkflowPerformance;
}

export type BacktestOpsRunMode = 'replay' | 'walk-forward' | 'current-like';

export type BacktestOpsBadgeState = 'ready' | 'watch' | 'blocked' | 'degraded';

export interface BacktestOpsRunSummary {
  id: string;
  label: string;
  mode: BacktestOpsRunMode;
  phase: 'completed' | 'snapshot';
  status: BacktestOpsBadgeState;
  progressPct: number;
  frameCount: number;
  warmupFrameCount: number;
  evaluationFrameCount: number;
  ideaRunCount: number;
  forwardReturnCount: number;
  costAdjustedHitRate: number;
  costAdjustedAvgReturnPct: number;
  avgRealityScore: number;
  avgExecutionPenaltyPct: number;
  nonTradableRate: number;
  portfolio: PortfolioAccountingSummary | null;
  coverageScore: number;
  qualityScore: number;
  executionScore: number;
  activityScore: number;
  confirmationReliability: number;
  currentVsReplayDrift: number;
  preferredHorizonHours: number | null;
  themeHorizonHours: number[];
  themeCount: number;
  uniqueSymbolCount: number;
  updatedAt: string;
  note?: string;
}

export interface BacktestOpsSnapshot {
  updatedAt: string;
  latestReplay: BacktestOpsRunSummary | null;
  latestWalkForward: BacktestOpsRunSummary | null;
  currentLike: BacktestOpsRunSummary | null;
  recentRuns: BacktestOpsRunSummary[];
  workflow: ReplayWorkflowPerformance;
  coverageLedger: CoverageLedgerSnapshot | null;
  themeProfiles: ReplayThemeProfile[];
  currentThemePerformance: CurrentThemePerformanceMetric[];
  portfolio: PortfolioAccountingSummary | null;
  derived: {
    qualityScore: number;
    executionScore: number;
    activityScore: number;
    coverageScore: number;
    driftScore: number;
    readinessScore: number;
  };
  badges: {
    quality: BacktestOpsBadgeState;
    execution: BacktestOpsBadgeState;
    activity: BacktestOpsBadgeState;
    coverage: BacktestOpsBadgeState;
    drift: BacktestOpsBadgeState;
  };
}

interface PersistedReplayAdaptationStore {
  snapshot: ReplayAdaptationSnapshot | null;
}

const REPLAY_ADAPTATION_KEY = 'replay-adaptation:v1';
const MAX_REPLAY_DIGESTS = 36;
const RUN_HALF_LIFE_DAYS = 45;
const HORIZON_BAR_MULTIPLIERS = [1, 2, 3, 5, 8, 13, 21];

let loaded = false;
let currentSnapshot: ReplayAdaptationSnapshot | null = null;

function nowIso(): string {
  return new Date().toISOString();
}

function asTs(value: string | null | undefined): number {
  const parsed = Date.parse(String(value || ''));
  return Number.isFinite(parsed) ? parsed : 0;
}

function clamp(value: number, min: number, max: number): number {
  if (Number.isNaN(value)) return min;
  return Math.min(max, Math.max(min, value));
}

function average(values: number[]): number {
  if (!values.length) return 0;
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function normalizeThemeId(value: string): string {
  return String(value || '').trim().toLowerCase();
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return Boolean(value) && typeof value === 'object' && !Array.isArray(value);
}

function readNumberFromKeys(source: Record<string, unknown>, keys: string[]): number | null {
  for (const key of keys) {
    const value = Number(source[key]);
    if (Number.isFinite(value)) return value;
  }
  return null;
}

function readFirstRecord(source: Record<string, unknown>, keys: string[]): Record<string, unknown> | null {
  for (const key of keys) {
    const candidate = source[key];
    if (isRecord(candidate)) return candidate;
  }
  return null;
}

function collectCurvePoints(source: Record<string, unknown>): Array<{ timestamp: string; nav: number }> {
  const curveKeys = ['equityCurve', 'navCurve', 'portfolioCurve', 'curve', 'series'];
  for (const key of curveKeys) {
    const candidate = source[key];
    if (!Array.isArray(candidate)) continue;
    const points = candidate
      .map((item) => {
        if (!isRecord(item)) return null;
        const timestamp = String(item.timestamp || item.time || item.at || item.date || '').trim();
        const nav = readNumberFromKeys(item, ['nav', 'equity', 'value', 'portfolioValue', 'capital']);
        if (!timestamp || nav == null || !Number.isFinite(nav) || nav <= 0) return null;
        return { timestamp, nav };
      })
      .filter((point): point is { timestamp: string; nav: number } => Boolean(point))
      .sort((left, right) => asTs(left.timestamp) - asTs(right.timestamp));
    if (points.length > 0) return points;
  }
  return [];
}

function buildPortfolioMetricsFromCurve(points: Array<{ timestamp: string; nav: number }>): Omit<PortfolioAccountingSummary, 'source' | 'available'> | null {
  if (!points.length) return null;
  const normalized = points
    .slice()
    .filter((point) => point.nav > 0 && Number.isFinite(point.nav))
    .sort((left, right) => asTs(left.timestamp) - asTs(right.timestamp));
  if (!normalized.length) return null;

  const startNav = normalized[0]!.nav;
  const endNav = normalized[normalized.length - 1]!.nav;
  const navChangePct = startNav > 0 ? ((endNav - startNav) / startNav) * 100 : null;

  let peak = startNav;
  let maxDrawdownPct = 0;
  for (const point of normalized) {
    peak = Math.max(peak, point.nav);
    if (peak > 0) {
      const drawdownPct = ((point.nav - peak) / peak) * 100;
      maxDrawdownPct = Math.min(maxDrawdownPct, drawdownPct);
    }
  }

  const firstTs = asTs(normalized[0]!.timestamp);
  const lastTs = asTs(normalized[normalized.length - 1]!.timestamp);
  const durationDays = Math.max(1, (lastTs - firstTs) / 86_400_000);
  const cagrPct = startNav > 0 && endNav > 0
    ? (Math.pow(endNav / startNav, 365 / durationDays) - 1) * 100
    : null;
  const returns: number[] = [];
  for (let index = 1; index < normalized.length; index += 1) {
    const previous = normalized[index - 1]!;
    const current = normalized[index]!;
    if (previous.nav > 0 && current.nav > 0) {
      returns.push((current.nav / previous.nav) - 1);
    }
  }
  const averageSpacingDays = normalized.length > 1
    ? Math.max(1 / 24, (lastTs - firstTs) / Math.max(1, normalized.length - 1) / 86_400_000)
    : 1;
  const periodsPerYear = clamp(365 / averageSpacingDays, 1, 365);
  const meanReturn = returns.length > 0 ? average(returns) : 0;
  const stdReturn = returns.length > 1
    ? Math.sqrt(average(returns.map((value) => (value - meanReturn) ** 2)))
    : 0;
  const sharpe = stdReturn > 0 ? (meanReturn / stdReturn) * Math.sqrt(periodsPerYear) : null;
  const annualizedVolatilityPct = stdReturn > 0 ? stdReturn * Math.sqrt(periodsPerYear) * 100 : null;

  return {
    weightedReturnPct: navChangePct,
    navStart: startNav,
    navEnd: endNav,
    navChangePct,
    cagrPct,
    maxDrawdownPct,
    sharpe,
    annualizedVolatilityPct,
    sampleCount: normalized.length,
    tradeCount: normalized.length,
    curvePointCount: normalized.length,
  };
}

function normalizePortfolioAccountingSummary(
  value: Partial<PortfolioAccountingSummary> & { source?: PortfolioAccountingSummary['source'] } | null | undefined,
): PortfolioAccountingSummary | null {
  if (!value) return null;
  const weightedReturnPct = Number.isFinite(Number(value.weightedReturnPct)) ? Number(value.weightedReturnPct) : null;
  const navStart = Number.isFinite(Number(value.navStart)) ? Number(value.navStart) : null;
  const navEnd = Number.isFinite(Number(value.navEnd)) ? Number(value.navEnd) : null;
  const navChangePct = Number.isFinite(Number(value.navChangePct))
    ? Number(value.navChangePct)
    : navStart != null && navEnd != null && navStart !== 0
      ? ((navEnd - navStart) / navStart) * 100
      : null;
  const cagrPct = Number.isFinite(Number(value.cagrPct)) ? Number(value.cagrPct) : null;
  const maxDrawdownPct = Number.isFinite(Number(value.maxDrawdownPct)) ? Number(value.maxDrawdownPct) : null;
  const sharpe = Number.isFinite(Number(value.sharpe)) ? Number(value.sharpe) : null;
  const annualizedVolatilityPct = Number.isFinite(Number(value.annualizedVolatilityPct))
    ? Number(value.annualizedVolatilityPct)
    : null;

  return {
    source: value.source || 'missing',
    available: value.source !== 'missing' && (
      weightedReturnPct != null
      || navStart != null
      || navEnd != null
      || navChangePct != null
      || cagrPct != null
      || maxDrawdownPct != null
      || sharpe != null
      || annualizedVolatilityPct != null
    ),
    weightedReturnPct,
    navStart,
    navEnd,
    navChangePct,
    cagrPct,
    maxDrawdownPct,
    sharpe,
    annualizedVolatilityPct,
    sampleCount: Math.max(0, Math.round(Number(value.sampleCount) || 0)),
    tradeCount: Math.max(0, Math.round(Number(value.tradeCount) || 0)),
    curvePointCount: Math.max(0, Math.round(Number(value.curvePointCount) || 0)),
  };
}

function readPortfolioAccountingSource(run: HistoricalReplayRun): Record<string, unknown> | null {
  const source: Record<string, unknown> = { ...run };
  const candidates = [
    source.portfolioAccounting,
    source.portfolioMetrics,
    source.portfolioSummary,
    source.portfolio,
    source.portfolioPerformance,
    source.accounting,
  ];
  for (const candidate of candidates) {
    if (!isRecord(candidate)) continue;
    const nested = readFirstRecord(candidate, ['summary', 'metrics', 'accounting']);
    return nested || candidate;
  }
  return null;
}

function summarizePortfolioAccountingSnapshot(
  snapshot: HistoricalReplayRun['portfolioAccounting'],
): PortfolioAccountingSummary | null {
  if (!snapshot) return null;
  const summary = snapshot.summary;
  const curveMetrics = buildPortfolioMetricsFromCurve(Array.isArray(snapshot.equityCurve)
    ? snapshot.equityCurve
      .map((point) => ({
        timestamp: String(point.timestamp || '').trim(),
        nav: Number(point.nav) || 0,
      }))
      .filter((point) => Boolean(point.timestamp) && point.nav > 0)
    : []);
  return normalizePortfolioAccountingSummary({
    source: 'run',
    weightedReturnPct: Number.isFinite(Number(summary.weightedCostAdjustedReturnPct))
      ? Number(summary.weightedCostAdjustedReturnPct)
      : Number.isFinite(Number(summary.weightedReturnPct))
        ? Number(summary.weightedReturnPct)
        : null,
    navStart: Number.isFinite(Number(summary.initialCapital))
      ? Number(summary.initialCapital)
      : curveMetrics?.navStart ?? null,
    navEnd: Number.isFinite(Number(summary.finalCapital))
      ? Number(summary.finalCapital)
      : curveMetrics?.navEnd ?? null,
    navChangePct: Number.isFinite(Number(summary.totalReturnPct))
      ? Number(summary.totalReturnPct)
      : curveMetrics?.navChangePct ?? null,
    cagrPct: Number.isFinite(Number(summary.cagrPct))
      ? Number(summary.cagrPct)
      : curveMetrics?.cagrPct ?? null,
    maxDrawdownPct: Number.isFinite(Number(summary.maxDrawdownPct))
      ? Number(summary.maxDrawdownPct)
      : curveMetrics?.maxDrawdownPct ?? null,
    sharpe: Number.isFinite(Number(summary.sharpeRatio))
      ? Number(summary.sharpeRatio)
      : curveMetrics?.sharpe ?? null,
    annualizedVolatilityPct: Number.isFinite(Number(summary.volatilityPct))
      ? Number(summary.volatilityPct)
      : curveMetrics?.annualizedVolatilityPct ?? null,
    sampleCount: Math.max(0, Math.round(Number(summary.selectedTradeCount ?? summary.tradeCount) || 0)),
    tradeCount: Math.max(0, Math.round(Number(summary.tradeCount) || 0)),
    curvePointCount: Array.isArray(snapshot.equityCurve) ? snapshot.equityCurve.length : curveMetrics?.curvePointCount ?? 0,
  });
}

function summarizeHistoricalRunPortfolioAccounting(run: HistoricalReplayRun): PortfolioAccountingSummary | null {
  const direct = summarizePortfolioAccountingSnapshot(run.portfolioAccounting);
  if (direct) return direct;

  const source = readPortfolioAccountingSource(run);
  if (!source) return null;

  const summary = readFirstRecord(source, ['summary', 'metrics', 'accounting']) || source;
  const curvePoints = collectCurvePoints(source);
  const curveMetrics = buildPortfolioMetricsFromCurve(curvePoints);
  return normalizePortfolioAccountingSummary({
    source: curveMetrics ? 'inferred' : 'missing',
    weightedReturnPct: readNumberFromKeys(summary, [
      'weightedReturnPct',
      'weightedCostAdjustedReturnPct',
      'weightedCostAdjustedSignedReturnPct',
      'weightedReturn',
      'weightedSignedReturnPct',
    ]) ?? null,
    navStart: readNumberFromKeys(summary, ['navStart', 'initialCapital', 'capitalStart']) ?? curveMetrics?.navStart ?? null,
    navEnd: readNumberFromKeys(summary, ['navEnd', 'finalCapital', 'capitalEnd']) ?? curveMetrics?.navEnd ?? null,
    navChangePct: readNumberFromKeys(summary, ['navChangePct', 'totalReturnPct', 'returnPct']) ?? curveMetrics?.navChangePct ?? null,
    cagrPct: readNumberFromKeys(summary, ['cagrPct']) ?? curveMetrics?.cagrPct ?? null,
    maxDrawdownPct: readNumberFromKeys(summary, ['maxDrawdownPct']) ?? curveMetrics?.maxDrawdownPct ?? null,
    sharpe: readNumberFromKeys(summary, ['sharpe', 'sharpeRatio']) ?? curveMetrics?.sharpe ?? null,
    annualizedVolatilityPct: readNumberFromKeys(summary, ['annualizedVolatilityPct', 'volatilityPct']) ?? curveMetrics?.annualizedVolatilityPct ?? null,
    sampleCount: Math.max(
      0,
      Math.round(
        readNumberFromKeys(summary, ['sampleCount', 'selectedTradeCount', 'tradeCount', 'ideaRunCount'])
        ?? curveMetrics?.sampleCount
        ?? 0,
      ),
    ),
    tradeCount: Math.max(
      0,
      Math.round(
        readNumberFromKeys(summary, ['tradeCount', 'selectedTradeCount', 'ideaRunCount'])
        ?? curveMetrics?.tradeCount
        ?? 0,
      ),
    ),
    curvePointCount: Math.max(0, Math.round(curvePoints.length || curveMetrics?.curvePointCount || 0)),
  });
}

function pickAvailablePortfolioSummary(
