function normalizeThemePolicy(policy?: ThemePolicyDefinition): ThemePolicyDefinition | undefined {
  if (!policy) return undefined;
  const normalizedSymbolAdjustments = Object.fromEntries(
    Object.entries(policy.symbolAdjustments || {})
      .map(([symbol, value]) => [String(symbol || '').trim().toUpperCase(), { ...value }])
      .filter(([symbol]) => Boolean(symbol)),
  );
  return {
    classification: policy.classification,
    trigger: policy.trigger
      ? {
        minTriggerHits: Math.max(1, Math.round(Number(policy.trigger.minTriggerHits) || 1)),
        minStress: clamp(Number(policy.trigger.minStress) || 0, 0, 1),
        requireDirectionalTerms: Array.isArray(policy.trigger.requireDirectionalTerms)
          ? policy.trigger.requireDirectionalTerms.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 12)
          : [],
      }
      : undefined,
    assets: policy.assets
      ? {
        maxPrimaryAssets: Math.max(0, Math.round(Number(policy.assets.maxPrimaryAssets) || 0)) || undefined,
        maxConfirmAssets: Math.max(0, Math.round(Number(policy.assets.maxConfirmAssets) || 0)) || undefined,
        maxHedgeAssets: Math.max(0, Math.round(Number(policy.assets.maxHedgeAssets) || 0)) || undefined,
      }
      : undefined,
    admission: policy.admission
      ? {
        rejectHitProbability: typeof policy.admission.rejectHitProbability === 'number' ? clamp(policy.admission.rejectHitProbability, 0, 1) : undefined,
        watchHitProbability: typeof policy.admission.watchHitProbability === 'number' ? clamp(policy.admission.watchHitProbability, 0, 1) : undefined,
        rejectExpectedReturnPct: typeof policy.admission.rejectExpectedReturnPct === 'number' ? Number(policy.admission.rejectExpectedReturnPct.toFixed(2)) : undefined,
        watchExpectedReturnPct: typeof policy.admission.watchExpectedReturnPct === 'number' ? Number(policy.admission.watchExpectedReturnPct.toFixed(2)) : undefined,
        rejectScore: typeof policy.admission.rejectScore === 'number' ? clamp(policy.admission.rejectScore, 0, 100) : undefined,
        watchScore: typeof policy.admission.watchScore === 'number' ? clamp(policy.admission.watchScore, 0, 100) : undefined,
      }
      : undefined,
    narrative: policy.narrative
      ? {
        enabled: policy.narrative.enabled !== false,
        minAlignmentScore: typeof policy.narrative.minAlignmentScore === 'number' ? clamp(policy.narrative.minAlignmentScore, 0, 100) : undefined,
        weakPenalty: typeof policy.narrative.weakPenalty === 'number' ? clamp(policy.narrative.weakPenalty, 0, 20) : undefined,
        mismatchPenalty: typeof policy.narrative.mismatchPenalty === 'number' ? clamp(policy.narrative.mismatchPenalty, 0, 30) : undefined,
      }
      : undefined,
    symbolAdjustments: Object.keys(normalizedSymbolAdjustments).length > 0 ? normalizedSymbolAdjustments : undefined,
  };
}

function inferThemeClassification(theme: ThemeRule): ThemeClassification {
  const hedgeCount = theme.assets.filter((asset) => asset.role === 'hedge' || asset.direction === 'hedge').length;
  const directionalCount = theme.assets.filter((asset) => asset.direction === 'long' || asset.direction === 'short').length;
  if (hedgeCount >= Math.max(2, directionalCount)) return 'hedge-heavy';
  if (hedgeCount > 0 && directionalCount > 0) return 'mixed';
  return 'directional';
}

export function resolveThemePolicy(theme: ThemeRule): Required<ThemePolicyDefinition> {
  const classification = theme.policy?.classification || inferThemeClassification(theme);
  const normalized = normalizeThemePolicy(theme.policy) || {};
  return {
    classification,
    trigger: {
      minTriggerHits: normalized.trigger?.minTriggerHits ?? (classification === 'hedge-heavy' ? 2 : classification === 'mixed' ? 2 : 1),
      minStress: normalized.trigger?.minStress ?? (classification === 'hedge-heavy' ? 0.3 : classification === 'mixed' ? 0.18 : 0),
      requireDirectionalTerms: normalized.trigger?.requireDirectionalTerms ?? [],
    },
    assets: {
      maxPrimaryAssets: normalized.assets?.maxPrimaryAssets ?? (classification === 'hedge-heavy' ? 1 : classification === 'mixed' ? 2 : 2),
      maxConfirmAssets: normalized.assets?.maxConfirmAssets ?? (classification === 'hedge-heavy' ? 1 : 2),
      maxHedgeAssets: normalized.assets?.maxHedgeAssets ?? (classification === 'directional' ? 1 : 2),
    },
    admission: {
      rejectHitProbability: normalized.admission?.rejectHitProbability ?? (classification === 'hedge-heavy' ? 0.46 : 0.44),
      watchHitProbability: normalized.admission?.watchHitProbability ?? (classification === 'hedge-heavy' ? 0.54 : 0.52),
      rejectExpectedReturnPct: normalized.admission?.rejectExpectedReturnPct ?? (classification === 'hedge-heavy' ? -0.05 : -0.2),
      watchExpectedReturnPct: normalized.admission?.watchExpectedReturnPct ?? (classification === 'hedge-heavy' ? 0.1 : 0.08),
      rejectScore: normalized.admission?.rejectScore ?? (classification === 'hedge-heavy' ? 42 : 38),
      watchScore: normalized.admission?.watchScore ?? (classification === 'hedge-heavy' ? 54 : 52),
    },
    narrative: {
      enabled: normalized.narrative?.enabled ?? classification !== 'directional',
      minAlignmentScore: normalized.narrative?.minAlignmentScore ?? (classification === 'hedge-heavy' ? 48 : 44),
      weakPenalty: normalized.narrative?.weakPenalty ?? 3,
      mismatchPenalty: normalized.narrative?.mismatchPenalty ?? 7,
    },
    symbolAdjustments: {
      ...SPECIAL_SYMBOL_POLICY,
      ...(normalized.symbolAdjustments || {}),
    },
  };
}

function extractThemeLexicon(theme: ThemeRule): string[] {
  const assetAliases = theme.assets.flatMap((asset) => {
    const catalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(asset.symbol));
    return catalog?.aliases || [];
  });
  return Array.from(new Set([
    ...theme.triggers,
    ...theme.sectors,
    ...theme.commodities,
    theme.label,
    ...assetAliases,
  ].map((item) => String(item || '').trim().toLowerCase()).filter(Boolean)));
}

function computeNarrativeAlignmentScore(candidate: EventCandidate, theme: ThemeRule, triggerHits: string[]): number {
  const text = normalize(String(candidate.text || ''));
  const lexicon = extractThemeLexicon(theme);
  if (!text || !lexicon.length) return triggerHits.length > 0 ? 55 : 0;
  const directionalTerms = resolveThemePolicy(theme).trigger.requireDirectionalTerms || [];
  const lexiconHits = lexicon.filter((term) => matchesThemeTrigger(text, term));
  const directionalHits = directionalTerms.filter((term) => matchesThemeTrigger(text, term));
  const symbolHits = candidate.matchedSymbols.filter((symbol) => themeHasAssetSymbol(theme, symbol));
  return clamp(
    Math.round(
      18
      + triggerHits.length * 14
      + lexiconHits.length * 5
      + directionalHits.length * 8
      + symbolHits.length * 11
      + candidate.corroborationQuality * 0.18
      + candidate.sourceDiversity * 0.08
      + candidate.marketStress * 14,
    ),
    0,
    100,
  );
}

function classifyNarrativeShadowState(theme: ThemeRule, narrativeAlignmentScore: number): NarrativeShadowState {
  const minAlignment = resolveThemePolicy(theme).narrative.minAlignmentScore || 48;
  if (narrativeAlignmentScore >= minAlignment) return 'aligned';
  if (narrativeAlignmentScore >= minAlignment - 10) return 'weak';
  return 'mismatch';
}

/**
 * Normalizes a theme's arrays (triggers, sectors, commodities, invalidation)
 * and assets, ensuring all values are properly trimmed and validated
 */
export function normalizeThemeDefinition(theme: InvestmentThemeDefinition): InvestmentThemeDefinition {
  return {
    id: String(theme.id || '').trim().toLowerCase(),
    label: String(theme.label || '').trim() || 'Untitled Theme',
    triggers: Array.isArray(theme.triggers) ? theme.triggers.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 20) : [],
    sectors: Array.isArray(theme.sectors) ? theme.sectors.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 10) : [],
    commodities: Array.isArray(theme.commodities) ? theme.commodities.map((item) => String(item || '').trim().toLowerCase()).filter(Boolean).slice(0, 10) : [],
    timeframe: String(theme.timeframe || '1d-7d').trim() || '1d-7d',
    thesis: String(theme.thesis || 'Automated theme proposal.').trim() || 'Automated theme proposal.',
    invalidation: Array.isArray(theme.invalidation) ? theme.invalidation.map((item) => String(item || '').trim()).filter(Boolean).slice(0, 6) : [],
    baseSensitivity: clamp(Number(theme.baseSensitivity) || 60, 25, 95),
    policy: normalizeThemePolicy(theme.policy),
    assets: dedupeThemeAssets(
      Array.isArray(theme.assets)
        ? theme.assets
          .map((asset) => ({
            symbol: String(asset.symbol || '').trim().toUpperCase(),
            name: String(asset.name || asset.symbol || '').trim() || String(asset.symbol || '').trim().toUpperCase(),
            assetKind: asset.assetKind,
            sector: String(asset.sector || 'cross-asset').trim().toLowerCase() || 'cross-asset',
            commodity: asset.commodity ? String(asset.commodity).trim().toLowerCase() : undefined,
            direction: asset.direction,
            role: asset.role,
          }))
          .filter((asset) => asset.symbol && asset.assetKind && asset.direction && asset.role)
        : [],
    ),
  };
}

/**
 * Returns the effective theme catalog: base THEME_RULES plus any automated themes
 */
export function listEffectiveThemeCatalog(): ThemeRule[] {
  return [
    ...THEME_RULES,
    ...Array.from(automatedThemes.values()).map((theme) => normalizeThemeDefinition(theme)),
  ];
}

/**
 * Returns a deep copy of the base investment themes (THEME_RULES)
 */
export function listBaseInvestmentThemes(): InvestmentThemeDefinition[] {
  return THEME_RULES.map((theme) => ({
    ...theme,
    triggers: theme.triggers.slice(),
    sectors: theme.sectors.slice(),
    commodities: theme.commodities.slice(),
    invalidation: theme.invalidation.slice(),
    assets: theme.assets.map((asset) => ({ ...asset })),
  }));
}

/**
 * Returns a deep copy of the automated investment themes
 */
export function listAutomatedInvestmentThemes(): InvestmentThemeDefinition[] {
  return Array.from(automatedThemes.values()).map((theme) => ({
    ...theme,
    triggers: theme.triggers.slice(),
    sectors: theme.sectors.slice(),
    commodities: theme.commodities.slice(),
    invalidation: theme.invalidation.slice(),
    assets: theme.assets.map((asset) => ({ ...asset })),
  }));
}

/**
 * Sets the automated theme catalog to the provided themes,
 * normalizing each one and filtering out invalid entries
 */
export function setAutomatedThemeCatalog(themes: InvestmentThemeDefinition[]): void {
  setAutomatedThemes(
    new Map(
      (themes || [])
        .map((theme) => normalizeThemeDefinition(theme))
        .filter((theme) => theme.id && theme.triggers.length > 0)
        .map((theme) => [theme.id, theme] as const),
    ),
  );
}

export function buildThemeMatchDetails(candidate: EventCandidate): ThemeMatchDetail[] {
  const themeCatalog = listEffectiveThemeCatalog();
  const shadowScores = scoreNarrativeShadowThemes(candidate, themeCatalog);
  const shadowByThemeId = new Map(shadowScores.map((row) => [row.themeId, row]));
  const topShadowTheme = shadowScores[0] || null;
  const directMatches: ThemeMatchDetail[] = [];
  const fallbackMatches: ThemeMatchDetail[] = [];
  const normalizedText = normalize(String(candidate.text || ''));

  for (const theme of themeCatalog) {
    const policy = resolveThemePolicy(theme);
    const requiredDirectionalTerms = policy.trigger.requireDirectionalTerms || [];
    const minTriggerHits = policy.trigger.minTriggerHits || 1;
    const minStress = policy.trigger.minStress || 0;
    const triggerHits = theme.triggers.filter((trigger) => matchesThemeTrigger(normalizedText, trigger));
    const directionalHits = requiredDirectionalTerms.filter((term) => matchesThemeTrigger(normalizedText, term));
    const narrativeAlignmentScore = computeNarrativeAlignmentScore(candidate, theme, triggerHits);
    const narrativeShadowState = classifyNarrativeShadowState(theme, narrativeAlignmentScore);
    const shadow = shadowByThemeId.get(theme.id);
    const narrativeShadowPosterior = shadow?.posterior ?? 0;
    const narrativeShadowDisagreement = topShadowTheme && topShadowTheme.themeId !== theme.id
      ? clamp(Number(((topShadowTheme.posterior - narrativeShadowPosterior) * 100).toFixed(2)), 0, 100)
      : 0;
    const triggerPass =
      triggerHits.length >= minTriggerHits
      && candidate.marketStress >= minStress
      && (requiredDirectionalTerms.length === 0 || directionalHits.length > 0);
    const fallbackSymbolHits = candidate.matchedSymbols.filter((symbol) => themeHasAssetSymbol(theme, symbol));
    const fallbackPass =
      !triggerPass
      && fallbackSymbolHits.length > 0
      && candidate.marketStress >= Math.max(minStress, 0.55);
    if (!triggerPass && !fallbackPass) continue;
    const score = Number((
      triggerHits.length * 16
      + fallbackSymbolHits.length * 10
      + narrativeAlignmentScore * 0.42
      + candidate.corroborationQuality * 0.12
      + candidate.eventIntensity * 0.08
      + candidate.aftershockIntensity * 10
      - (narrativeShadowState === 'mismatch' ? 8 : narrativeShadowState === 'weak' ? 3 : 0)
    ).toFixed(2));
    const detail: ThemeMatchDetail = {
      theme,
      triggerHits,
      triggerHitCount: triggerHits.length,
      narrativeAlignmentScore,
      narrativeShadowState,
      narrativeShadowPosterior,
      narrativeShadowDisagreement,
      narrativeShadowTopThemeId: topShadowTheme?.themeId ?? null,
      score,
      matchedBy: triggerPass ? 'trigger' : 'fallback-symbol',
    };
    if (triggerPass) {
      directMatches.push(detail);
    } else {
      fallbackMatches.push(detail);
    }
  }

  const ranked = (directMatches.length > 0 ? directMatches : fallbackMatches)
    .sort((left, right) => right.score - left.score || right.triggerHitCount - left.triggerHitCount)
    .slice(0, candidate.marketStress >= 0.65 ? 4 : 3);
  return ranked;
}

/**
 * Finds themes that match an EventCandidate by trigger matching,
 * and falls back to symbol matching if market stress is high
 */
export function findMatchingThemes(candidate: EventCandidate): ThemeRule[] {
  return buildThemeMatchDetails(candidate).map((match) => match.theme);
}

/**
 * Finds a theme rule by its id from the effective catalog
 */
export function getThemeRule(themeId: string): ThemeRule | null {
  return listEffectiveThemeCatalog().find((theme) => theme.id === themeId) || null;
}

/**
 * Gets the effective theme assets including both base assets and accepted candidate reviews
 */
export function getEffectiveThemeAssets(theme: ThemeRule): ThemeAssetDefinition[] {
  const accepted = Array.from(candidateReviews.values())
    .filter((review) => review.themeId === theme.id && review.status === 'accepted')
    .map(reviewToThemeAsset);
  return dedupeThemeAssets([...theme.assets, ...accepted]);
}

export function selectThemeAssetsForCandidate(
  theme: ThemeRule,
  candidate: EventCandidate,
  matchDetail?: ThemeMatchDetail | null,
): ThemeAssetDefinition[] {
  const policy = resolveThemePolicy(theme);
  const symbolAdjustments = policy.symbolAdjustments;
  const maxPrimaryAssets = policy.assets.maxPrimaryAssets || 2;
  const maxConfirmAssets = policy.assets.maxConfirmAssets || 2;
  const maxHedgeAssets = policy.assets.maxHedgeAssets || 1;
  const assets = getEffectiveThemeAssets(theme)
    .filter((asset) => {
      const symbolRule = symbolAdjustments[String(asset.symbol || '').trim().toUpperCase()];
      if (!symbolRule?.requireRiskOff) return true;
      return candidate.marketStress >= 0.45;
    });
  const ranked = assets.slice().sort((left, right) => {
    const leftCatalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(left.symbol));
    const rightCatalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(right.symbol));
    const leftLiquidity = leftCatalog?.liquidityTier === 'high' ? 3 : leftCatalog?.liquidityTier === 'medium' ? 2 : 1;
    const rightLiquidity = rightCatalog?.liquidityTier === 'high' ? 3 : rightCatalog?.liquidityTier === 'medium' ? 2 : 1;
    const leftRole = left.role === 'primary' ? 3 : left.role === 'confirm' ? 2 : 1;
    const rightRole = right.role === 'primary' ? 3 : right.role === 'confirm' ? 2 : 1;
    return rightRole - leftRole || rightLiquidity - leftLiquidity;
  });
  const picked: ThemeAssetDefinition[] = [];
  let primaryCount = 0;
  let confirmCount = 0;
  let hedgeCount = 0;
  for (const asset of ranked) {
    const nextPrimary = asset.role === 'primary' ? primaryCount + 1 : primaryCount;
    const nextConfirm = asset.role === 'confirm' ? confirmCount + 1 : confirmCount;
    const nextHedge = asset.role === 'hedge' ? hedgeCount + 1 : hedgeCount;
    if (nextPrimary > maxPrimaryAssets) continue;
    if (nextConfirm > maxConfirmAssets) continue;
    if (nextHedge > maxHedgeAssets) continue;
    if (
      policy.classification === 'hedge-heavy'
      && matchDetail?.narrativeShadowState === 'mismatch'
      && asset.role === 'hedge'
      && hedgeCount > 0
    ) {
      continue;
    }
    picked.push(asset);
    primaryCount = nextPrimary;
    confirmCount = nextConfirm;
    hedgeCount = nextHedge;
  }
  return picked.length > 0 ? picked : ranked.slice(0, 2);
}

/**
 * Checks if a theme has a specific asset symbol (including accepted candidates)
 */
export function themeHasAssetSymbol(theme: ThemeRule, symbol: string): boolean {
  const normalizedSymbol = normalize(symbol);
  return getEffectiveThemeAssets(theme).some((asset) => normalize(asset.symbol) === normalizedSymbol);
}

/**
 * Builds a lookup map from normalized symbols to watchlist entries
 */
export function buildWatchlistLookup(): Map<string, { symbol: string; name?: string }> {
  const lookup = new Map<string, { symbol: string; name?: string }>();
  for (const entry of getMarketWatchlistEntries()) {
    lookup.set(normalize(entry.symbol), { symbol: entry.symbol, name: entry.name });
  }
  return lookup;
}

/**
 * Auto-promote discovered patterns to themes.
 * Called periodically to check if any discovered patterns qualify as themes.
 */
export function promoteDiscoveredPatternsToThemes(): InvestmentThemeDefinition[] {
  const patterns = getSignificantPatterns(5, 1.5); // At least 5 samples, t-stat >= 1.5
  const promoted: InvestmentThemeDefinition[] = [];
  const existingIds = new Set(listEffectiveThemeCatalog().map(t => t.id));

  // Group patterns by fingerprint (same news type -> same theme)
  const byFingerprint = new Map<string, DiscoveredLink[]>();
  for (const p of patterns) {
    const existing = byFingerprint.get(p.clusterFingerprint) || [];
    existing.push(p);
    byFingerprint.set(p.clusterFingerprint, existing);
  }

  for (const [fpId, links] of byFingerprint) {
    const themeId = `discovered-${fpId}`;
    if (existingIds.has(themeId)) continue;
    if (links.length < 2) continue; // Need at least 2 symbol connections

    // Build theme from discovered links
    const assets: ThemeAssetDefinition[] = links.slice(0, 6).map(link => ({
      symbol: link.symbol,
      name: link.symbol,
      assetKind: 'etf' as const,
      sector: 'discovered',
      commodity: undefined,
      direction: link.direction as 'long' | 'short',
      role: (link.tStat > 2 ? 'primary' : 'confirm') as 'primary' | 'confirm' | 'hedge',
    }));

    // Best horizon across all links
    const bestLink = links.reduce((a, b) => Math.abs(a.tStat) > Math.abs(b.tStat) ? a : b);
    const timeframe = `${Math.max(1, Math.floor(bestLink.horizonHours / 24))}d-${Math.ceil(bestLink.horizonHours / 24) * 2}d`;

    // Extract triggers from fingerprint
    const triggers = fpId.split('-').filter(t => t.length > 2);

    promoted.push({
      id: themeId,
      label: `Discovered: ${fpId}`,
      triggers,
      sectors: ['discovered'],
      commodities: [],
      timeframe,
      thesis: `Auto-discovered pattern: ${fpId} correlates with ${links.map(l => l.symbol).join(', ')} at ${bestLink.horizonHours}h horizon (t=${bestLink.tStat.toFixed(1)}, n=${bestLink.sampleCount})`,
      invalidation: ['Pattern breaks down', 'Correlation becomes insignificant'],
      baseSensitivity: clamp(Math.round(50 + bestLink.tStat * 5), 25, 80),
      assets,
    });
  }

  // Register promoted themes
  if (promoted.length > 0) {
    const existingAutomated = Array.from(automatedThemes.values()).filter(t => t.id.startsWith('discovered-'));
    // Keep max 10 discovered themes, remove oldest if needed
    const combined = [...existingAutomated, ...promoted].slice(-10);
    // Preserve non-discovered automated themes and add discovered ones
    const nonDiscovered = Array.from(automatedThemes.values()).filter(t => !t.id.startsWith('discovered-'));
    setAutomatedThemeCatalog([...nonDiscovered, ...combined]);
  }

  return promoted;
}

/**
 * User-customizable market watchlist (additive).
 *
 * Stores a list of extra tickers the user wants to track beyond the defaults.
 * Optional friendly label is supported (used as the displayed name).
 */

export interface MarketWatchlistEntry {
  symbol: string;
  /** Friendly label shown in the UI (maps to MarketData.name). */
  name?: string;
  /** Optional short display code (maps to MarketData.display). Defaults to symbol. */
  display?: string;
}

const STORAGE_KEY = 'wm-market-watchlist-v1';
export const MARKET_WATCHLIST_EVENT = 'wm-market-watchlist-changed';

function safeParseJson<T>(raw: string | null): T | null {
  if (!raw) return null;
  try { return JSON.parse(raw) as T; } catch { return null; }
}

function normalizeSymbol(raw: string): string {
  // Allow common finnhub/yahoo formats: ^GSPC, BRK-B, GC=F, BTCUSD, etc.
  // Only trim whitespace and remove internal spaces.
  return raw.trim().replace(/\s+/g, '');
}

function normalizeName(raw: string | undefined): string | undefined {
  const v = (raw || '').trim();
  return v ? v : undefined;
}

function coerceEntry(v: unknown): MarketWatchlistEntry | null {
  if (typeof v === 'string') {
    const sym = normalizeSymbol(v);
    if (!sym) return null;
    return { symbol: sym };
  }
  if (v && typeof v === 'object') {
    const obj = v as any;
    const sym = normalizeSymbol(String(obj.symbol || ''));
    if (!sym) return null;
    const name = normalizeName(typeof obj.name === 'string' ? obj.name : undefined);
    const display = normalizeName(typeof obj.display === 'string' ? obj.display : undefined);
    return { symbol: sym, ...(name ? { name } : {}), ...(display ? { display } : {}) };
  }
  return null;
}

export function getMarketWatchlistEntries(): MarketWatchlistEntry[] {
  try {
    const parsed = safeParseJson<unknown>(localStorage.getItem(STORAGE_KEY));
    if (Array.isArray(parsed)) {
      const entries: MarketWatchlistEntry[] = [];
      for (const item of parsed) {
        const e = coerceEntry(item);
        if (e) entries.push(e);
      }
      return entries;
    }
  } catch {
    // ignore
  }
  return [];
}

export function setMarketWatchlistEntries(entries: MarketWatchlistEntry[]): void {
  // Clean, de-dupe by symbol but keep order.
  const seen = new Set<string>();
  const out: MarketWatchlistEntry[] = [];

  for (const raw of entries || []) {
    const sym = normalizeSymbol(raw.symbol || '');
    if (!sym || seen.has(sym)) continue;
    seen.add(sym);

    const name = normalizeName(raw.name);
    const display = normalizeName(raw.display);

    out.push({ symbol: sym, ...(name ? { name } : {}), ...(display ? { display } : {}) });
    if (out.length >= 50) break;
  }

  try {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(out));
  } catch {
    // ignore
  }

  window.dispatchEvent(new CustomEvent(MARKET_WATCHLIST_EVENT, { detail: { entries: out } }));
}

export function resetMarketWatchlist(): void {
  try { localStorage.removeItem(STORAGE_KEY); } catch { /* ignore */ }
  window.dispatchEvent(new CustomEvent(MARKET_WATCHLIST_EVENT, { detail: { entries: [] } }));
}

export function subscribeMarketWatchlistChange(cb: (entries: MarketWatchlistEntry[]) => void): () => void {
  const handler = (e: Event) => {
    const detail = (e as CustomEvent).detail as { entries?: unknown } | undefined;
    if (Array.isArray(detail?.entries)) {
      const coerced: MarketWatchlistEntry[] = [];
      for (const it of detail!.entries!) {
        const ce = coerceEntry(it);
        if (ce) coerced.push(ce);
      }
      cb(coerced);
      return;
    }
    cb(getMarketWatchlistEntries());
  };
  window.addEventListener(MARKET_WATCHLIST_EVENT, handler);
  return () => window.removeEventListener(MARKET_WATCHLIST_EVENT, handler);
}

export function parseMarketWatchlistInput(text: string): MarketWatchlistEntry[] {
  // Accept comma or newline-separated entries.
  // Friendly label format: SYMBOL|Label (ex: TSLA|Tesla)
  const rawItems = text
    .split(/[\n,]+/g)
    .map((s) => s.trim())
    .filter(Boolean);

  const entries: MarketWatchlistEntry[] = [];

  for (const item of rawItems) {
    const [left, ...rest] = item.split('|');
    const symbol = normalizeSymbol(left || '');
    if (!symbol) continue;
    const name = normalizeName(rest.join('|'));
    entries.push({ symbol, ...(name ? { name } : {}) });
  }

  return entries;
}

/**
 * Pattern Discovery Engine
 * Finds statistically significant news→asset price reactions
 * without requiring predefined themes or keywords.
 */

export interface DiscoveredLink {
  id: string;
  clusterFingerprint: string;  // normalized cluster descriptor
  symbol: string;
  horizonHours: number;
  avgReturnPct: number;
  sampleCount: number;
  winRate: number;
  tStat: number;
  direction: 'long' | 'short';
  firstSeen: string;
  lastSeen: string;
  samples: Array<{ timestamp: string; returnPct: number }>;
}

export interface ClusterFingerprint {
  id: string;
  topTerms: string[];        // TF-IDF top nouns (no predefined keywords)
  sentiment: number;          // -1 to +1
  sourceRegions: string[];
  sourceCount: number;
  intensity: number;
  rawTitle: string;
}

const MAX_SAMPLES_PER_LINK = 100;
const MAX_DISCOVERED_LINKS = 5000;

// Store for discovered patterns
const discoveredLinks = new Map<string, DiscoveredLink>();
const fingerprintHistory = new Map<string, ClusterFingerprint[]>();

/**
 * Build a fingerprint from a cluster without using predefined keywords.
 * Uses TF-IDF-like term extraction from the cluster title/text.
 */
export function buildFingerprint(cluster: {
  primaryTitle?: string;
  title?: string;
  primarySource?: string;
  sourceCount?: number;
  region?: string;
  isAlert?: boolean;
}): ClusterFingerprint {
  const title = String(cluster.primaryTitle || cluster.title || '').trim();
  // Extract meaningful terms (>3 chars, not stopwords)
  const stopwords = new Set(['the','and','for','are','but','not','you','all','can','had','her','was','one','our','out','has','have','been','will','with','that','this','from','they','were','said','each','make','like','than','them','some','just','about','would','could','should','into','over','after','before','these','those','other','which','their','there','when','what','more','most','also','very','much','many','such','only','then','being','both','same','even','still','well','back','down','here','where','every','while','between','through','during','under','around','without','within','along','another','against','because','since','until','among','across','above','below','already','always','never','often','sometimes','usually','however','therefore','although','whether','either','neither','rather','quite','enough','perhaps','indeed','actually','certainly','probably','especially','particularly','generally','specifically','basically','essentially','simply','merely','nearly','almost','approximately','relatively','fairly']);
  const terms = title.toLowerCase()
    .replace(/[^a-z\s]/g, ' ')
    .split(/\s+/)
    .filter(w => w.length > 3 && !stopwords.has(w));

  // Count term frequency for this cluster
  const termFreq = new Map<string, number>();
  for (const term of terms) {
    termFreq.set(term, (termFreq.get(term) || 0) + 1);
  }
  const topTerms = [...termFreq.entries()]
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([term]) => term);

  // Simple sentiment from keyword presence
  const posWords = ['peace','deal','agreement','growth','rise','surge','gain','profit','recovery'];
  const negWords = ['war','attack','crisis','collapse','crash','threat','kill','destroy','sanction','block'];
  const posCount = terms.filter(t => posWords.includes(t)).length;
  const negCount = terms.filter(t => negWords.includes(t)).length;
  const sentiment = posCount === 0 && negCount === 0 ? 0 : (posCount - negCount) / Math.max(1, posCount + negCount);

  return {
    id: topTerms.slice(0, 3).join('-') || 'unknown',
    topTerms,
    sentiment,
    sourceRegions: cluster.region ? [cluster.region] : [],
    sourceCount: cluster.sourceCount || 1,
    intensity: cluster.isAlert ? 80 : 50,
    rawTitle: title.substring(0, 120),
  };
}

/**
 * Scan for lead-lag correlations between clusters and asset prices.
 * This is the core discovery function — no predefined rules needed.
 */
export function scanLeadLagCorrelations(args: {
  clusters: Array<{ primaryTitle?: string; title?: string; primarySource?: string; sourceCount?: number; region?: string; isAlert?: boolean; firstSeen?: string | Date }>;
  priceHistory: Map<string, Array<{ timestamp: number; price: number }>>;
  horizons: number[];  // hours to check: [6, 12, 24, 48, 72]
  currentTimestamp: string;
}): DiscoveredLink[] {
  const { clusters, priceHistory, horizons, currentTimestamp } = args;
  const currentTs = Date.parse(currentTimestamp);
  const newLinks: DiscoveredLink[] = [];

  for (const cluster of clusters) {
    const fp = buildFingerprint(cluster);
    const clusterTs = cluster.firstSeen
      ? (typeof cluster.firstSeen === 'string' ? Date.parse(cluster.firstSeen) : cluster.firstSeen.getTime())
      : currentTs;

    for (const [symbol, prices] of priceHistory) {
      // Find price at cluster time
      const entryPrice = findPriceNear(prices, clusterTs);
      if (!entryPrice) continue;

      for (const horizon of horizons) {
        const exitTs = clusterTs + horizon * 3600 * 1000;
        if (exitTs > currentTs) continue; // Can't look into future

        const exitPrice = findPriceNear(prices, exitTs);
        if (!exitPrice) continue;

        const returnPct = ((exitPrice - entryPrice) / entryPrice) * 100;
        const linkKey = `${fp.id}::${symbol}::${horizon}h`;

        // Update or create discovered link
        const existing = discoveredLinks.get(linkKey);
        if (existing) {
          existing.samples.push({ timestamp: currentTimestamp, returnPct });
          if (existing.samples.length > MAX_SAMPLES_PER_LINK) {
            existing.samples = existing.samples.slice(-MAX_SAMPLES_PER_LINK);
          }
          existing.sampleCount = existing.samples.length;
          existing.avgReturnPct = existing.samples.reduce((s, r) => s + r.returnPct, 0) / existing.samples.length;
          existing.winRate = existing.samples.filter(r => r.returnPct > 0).length / existing.samples.length;
          existing.lastSeen = currentTimestamp;
          // T-statistic
          const mean = existing.avgReturnPct;
          const variance = existing.samples.reduce((s, r) => s + (r.returnPct - mean) ** 2, 0) / Math.max(1, existing.samples.length - 1);
          existing.tStat = variance > 0 ? (mean / Math.sqrt(variance / existing.samples.length)) : 0;
          existing.direction = existing.avgReturnPct >= 0 ? 'long' : 'short';
        } else {
          const newLink: DiscoveredLink = {
            id: linkKey,
            clusterFingerprint: fp.id,
            symbol,
            horizonHours: horizon,
            avgReturnPct: returnPct,
            sampleCount: 1,
            winRate: returnPct > 0 ? 1 : 0,
            tStat: 0,
            direction: returnPct >= 0 ? 'long' : 'short',
            firstSeen: currentTimestamp,
            lastSeen: currentTimestamp,
            samples: [{ timestamp: currentTimestamp, returnPct }],
          };
          discoveredLinks.set(linkKey, newLink);
          newLinks.push(newLink);
        }
      }
    }
  }

  // Bound the discoveredLinks map to prevent unbounded growth
  if (discoveredLinks.size > MAX_DISCOVERED_LINKS) {
    const toRemove = Math.floor(discoveredLinks.size * 0.2);
    let removed = 0;
    for (const key of discoveredLinks.keys()) {
      if (removed >= toRemove) break;
      discoveredLinks.delete(key);
      removed++;
    }
  }

  return newLinks;
}

function findPriceNear(prices: Array<{ timestamp: number; price: number }>, targetTs: number): number | null {
  let best: { timestamp: number; price: number } | null = null;
  let bestDist = Infinity;
  for (const p of prices) {
    const dist = Math.abs(p.timestamp - targetTs);
    if (dist < bestDist && dist < 24 * 3600 * 1000) { // Within 24h
      best = p;
      bestDist = dist;
    }
  }
  return best?.price ?? null;
}

/**
 * Filter for statistically significant patterns only.
 */
export function getSignificantPatterns(minSamples = 3, minAbsTStat = 1.2): DiscoveredLink[] {
  return [...discoveredLinks.values()]
    .filter(link => link.sampleCount >= minSamples && Math.abs(link.tStat) >= minAbsTStat)
    .sort((a, b) => Math.abs(b.tStat) - Math.abs(a.tStat));
}

/**
 * Get all discovered links (for persistence/inspection).
 */
export function getAllDiscoveredLinks(): Map<string, DiscoveredLink> {
  return discoveredLinks;
}

/**
 * Find similar fingerprints in history.
 */
export function findSimilarFingerprints(fp: ClusterFingerprint, threshold = 0.5): ClusterFingerprint[] {
  const allFps = [...fingerprintHistory.values()].flat();
  return allFps.filter(other => {
    const commonTerms = fp.topTerms.filter(t => other.topTerms.includes(t)).length;
    const similarity = commonTerms / Math.max(1, Math.max(fp.topTerms.length, other.topTerms.length));
    return similarity >= threshold && other.id !== fp.id;
  });
}

/**
 * Register a cluster fingerprint in history.
 */
export function registerFingerprint(fp: ClusterFingerprint): void {
  const existing = fingerprintHistory.get(fp.id) || [];
  existing.push(fp);
  if (existing.length > 100) existing.shift();
  fingerprintHistory.set(fp.id, existing);
}

/**
 * Restore discovered links from persisted storage.
 */
export function restoreDiscoveredLinks(data: Record<string, DiscoveredLink>): void {
  for (const [key, link] of Object.entries(data)) {
    if (link.samples && link.samples.length > MAX_SAMPLES_PER_LINK) {
      link.samples = link.samples.slice(-MAX_SAMPLES_PER_LINK);
    }
    discoveredLinks.set(key, link);
  }
}

/**
 * Restore fingerprint history from persisted storage.
 */
export function restoreFingerprints(data: Record<string, ClusterFingerprint[]>): void {
  for (const [key, fps] of Object.entries(data)) {
    fingerprintHistory.set(key, fps);
  }
}

/**
 * Get all fingerprint history (for persistence).
 */
export function getAllFingerprints(): Map<string, ClusterFingerprint[]> {
  return fingerprintHistory;
}

import { getSignificantPatterns } from '../pattern-discovery';
import type { EventCandidate, InvestmentThemeDefinition, NarrativeFactorShadowThemeScore } from './types';
import { UNIVERSE_ASSET_CATALOG } from './constants';
import { clamp, matchesThemeTrigger, normalize } from './utils';

const TOKEN_STOPWORDS = new Set([
  'the', 'and', 'for', 'with', 'from', 'amid', 'after', 'over', 'near', 'about', 'against',
  'this', 'that', 'have', 'more', 'than', 'their', 'its', 'into', 'under', 'while', 'when',
  'will', 'said', 'says', 'report', 'reports', 'breaking', 'latest', 'update', 'updates',
]);

function tokenize(value: string): string[] {
  return Array.from(
    new Set(
      normalize(value)
        .split(/[^a-z0-9-]+/g)
        .filter((token) => token.length >= 3 && !TOKEN_STOPWORDS.has(token)),
    ),
  ).slice(0, 64);
}

function overlapCount(left: Iterable<string>, right: Iterable<string>): number {
  const rightSet = right instanceof Set ? right : new Set(right);
  let count = 0;
  for (const token of left) {
    if (rightSet.has(token)) count += 1;
  }
  return count;
}

function themeLexicon(theme: InvestmentThemeDefinition): Set<string> {
  const assetAliases = theme.assets.flatMap((asset) => {
    const catalog = UNIVERSE_ASSET_CATALOG.find((entry) => normalize(entry.symbol) === normalize(asset.symbol));
    return [asset.symbol, asset.name, ...(catalog?.aliases || [])];
  });
  return new Set([
    ...theme.triggers,
    ...theme.sectors,
    ...theme.commodities,
    theme.label,
    theme.thesis,
    ...assetAliases,
  ].flatMap((entry) => tokenize(String(entry || ''))));
}

function softmax(values: number[]): number[] {
  if (values.length === 0) return [];
  const max = Math.max(...values);
  const exps = values.map((value) => Math.exp(value - max));
  const total = exps.reduce((sum, value) => sum + value, 0);
  return exps.map((value) => value / Math.max(total, 1e-9));
}

export function scoreNarrativeShadowThemes(
  candidate: EventCandidate,
  themeCatalog: InvestmentThemeDefinition[],
): NarrativeFactorShadowThemeScore[] {
  const candidateTerms = new Set([
    ...tokenize(candidate.text || ''),
    ...candidate.graphTerms.flatMap((term) => tokenize(String(term || ''))),
    ...candidate.matchedSymbols.map((symbol) => normalize(symbol)),
  ]);
  const patterns = getSignificantPatterns(2, 0.8);
  const rawRows = themeCatalog.map((theme) => {
    const lexicon = themeLexicon(theme);
    const lexiconHitCount = overlapCount(candidateTerms, lexicon);
    const directPhraseHits = theme.triggers.filter((trigger) => matchesThemeTrigger(candidate.text || '', trigger)).length;
    const symbolOverlapCount = candidate.matchedSymbols.filter((symbol) => theme.assets.some((asset) => normalize(asset.symbol) === normalize(symbol))).length;
    const themeAssetSet = new Set(theme.assets.map((asset) => normalize(asset.symbol)));
    const patternMatches = patterns.filter((pattern) => {
      if (!themeAssetSet.has(normalize(pattern.symbol))) return false;
      const fpTerms = String(pattern.clusterFingerprint || '').split('-').map((term) => normalize(term)).filter(Boolean);
      return overlapCount(candidateTerms, fpTerms) > 0;
    });
    const patternSupportScore = Number(patternMatches.reduce((sum, pattern) => (
      sum
      + Math.min(2.5, Math.abs(pattern.tStat) / 2.2)
      + Math.min(1.8, pattern.sampleCount / 6)
      + Math.min(1.5, Math.abs(pattern.avgReturnPct) / 0.8)
    ), 0).toFixed(2));
    const alignmentScore = clamp(Math.round(
      16
      + directPhraseHits * 14
      + lexiconHitCount * 7
      + symbolOverlapCount * 12
      + patternSupportScore * 7
      + candidate.corroborationQuality * 0.1
      + candidate.marketStress * 10
      + candidate.eventIntensity * 0.06,
    ), 0, 100);
    const rawScore = Number((
      directPhraseHits * 1.4
      + lexiconHitCount * 0.75
      + symbolOverlapCount * 1.2
      + patternSupportScore * 0.9
      + candidate.marketStress * 0.35
      + candidate.aftershockIntensity * 0.18
    ).toFixed(4));
    return {
      themeId: theme.id,
      themeLabel: theme.label,
      rawScore,
      posterior: 0,
      alignmentScore,
      patternSupportScore: Number(patternSupportScore.toFixed(2)),
      lexiconHitCount: directPhraseHits + lexiconHitCount,
      symbolOverlapCount,
      evidence: [
        directPhraseHits > 0 ? `triggerHits=${directPhraseHits}` : '',
        lexiconHitCount > 0 ? `tokenHits=${lexiconHitCount}` : '',
        symbolOverlapCount > 0 ? `symbolHits=${symbolOverlapCount}` : '',
        patternSupportScore > 0 ? `patternSupport=${patternSupportScore.toFixed(1)}` : '',
      ].filter(Boolean),
    };
  });
  const posteriors = softmax(rawRows.map((row) => row.rawScore));
  return rawRows
    .map((row, index) => ({ ...row, posterior: Number(posteriors[index]!.toFixed(6)) }))
    .sort((left, right) => right.posterior - left.posterior || right.alignmentScore - left.alignmentScore);
}

import { clamp } from './math-utils';

export interface MetaWeights {
  featureNames: string[];
  weights: number[];
  bias: number;
}

export interface CredibilityWeights {
  featureNames: string[];
  weights: number[];
  bias: number;
}

export interface MetaTrainingExample {
  confidence: number;
  confirmation: number;
  reality: number;
  replayHitRate: number;
  currentHitRate: number;
  coverage: number;
  bandit: number;
  transfer: number;
  stability: number;
  falsePositivePenalty: number;
  driftPenalty: number;
  hit: boolean;
}

export interface CredibilityTrainingExample {
  corroboration: number;
  historicalAccuracy: number;
  posteriorAccuracy: number;
  truthAgreement: number;
  emReliability: number;
  feedHealth: number;
  inversePropaganda: number;
  actualCredibility: number;
}

export type WeightVector = MetaWeights | CredibilityWeights;

const META_FEATURE_NAMES = [
  'confidence',
  'confirmation',
  'reality',
  'replayHitRate',
  'currentHitRate',
  'coverage',
  'bandit',
  'transfer',
  'stability',
  'falsePositivePenalty',
  'driftPenalty',
] as const;

const CREDIBILITY_FEATURE_NAMES = [
  'corroboration',
  'historicalAccuracy',
  'posteriorAccuracy',
  'truthAgreement',
  'emReliability',
  'feedHealth',
  'inversePropaganda',
] as const;

const META_LEARNING_RATE = 0.01;
const META_ITERATIONS = 1000;
const META_L2_LAMBDA = 0.01;
const CREDIBILITY_L2_LAMBDA = 0.1;

function isFiniteNumber(value: unknown): value is number {
  return typeof value === 'number' && Number.isFinite(value);
}

function safeNumber(value: unknown, fallback = 0): number {
  return isFiniteNumber(value) ? value : fallback;
}

function sigmoid(value: number): number {
  const bounded = clamp(value, -30, 30);
  return 1 / (1 + Math.exp(-bounded));
}

function dotProduct(left: number[], right: number[]): number {
  let total = 0;
  for (let index = 0; index < left.length; index += 1) {
    total += safeNumber(left[index]) * safeNumber(right[index]);
  }
  return total;
}

function transpose(matrix: number[][]): number[][] {
  if (matrix.length === 0) return [];
  const columnCount = matrix[0]?.length ?? 0;
  return Array.from({ length: columnCount }, (_, columnIndex) =>
    matrix.map((row) => safeNumber(row[columnIndex])));
}

function multiplyMatrices(left: number[][], right: number[][]): number[][] {
  if (left.length === 0 || right.length === 0) return [];
  const sharedCount = right.length;
  const columnCount = right[0]?.length ?? 0;
  return left.map((row) =>
    Array.from({ length: columnCount }, (_, columnIndex) => {
      let total = 0;
      for (let sharedIndex = 0; sharedIndex < sharedCount; sharedIndex += 1) {
        total += safeNumber(row[sharedIndex]) * safeNumber(right[sharedIndex]?.[columnIndex]);
      }
      return total;
    }));
}

function multiplyMatrixVector(matrix: number[][], vector: number[]): number[] {
  return matrix.map((row) => dotProduct(row, vector));
}

function invertMatrix(matrix: number[][]): number[][] {
  const size = matrix.length;
  const augmented = matrix.map((row, rowIndex) => ([
    ...row,
    ...Array.from({ length: size }, (_, columnIndex) => (rowIndex === columnIndex ? 1 : 0)),
  ]));

  for (let pivotIndex = 0; pivotIndex < size; pivotIndex += 1) {
    let pivotRow = pivotIndex;
    while (pivotRow < size && Math.abs(augmented[pivotRow]?.[pivotIndex] || 0) < 1e-12) {
      pivotRow += 1;
    }
    if (pivotRow === size) {
      throw new Error('[weight-learner] ridge regression matrix is singular');
    }
    if (pivotRow !== pivotIndex) {
      [augmented[pivotIndex], augmented[pivotRow]] = [augmented[pivotRow]!, augmented[pivotIndex]!];
    }

    const pivot = safeNumber(augmented[pivotIndex]![pivotIndex]);
    if (Math.abs(pivot) < 1e-12 || !Number.isFinite(pivot)) {
      throw new Error('[weight-learner] ridge regression matrix pivot is unstable');
    }
    for (let columnIndex = 0; columnIndex < size * 2; columnIndex += 1) {
      augmented[pivotIndex]![columnIndex] = safeNumber(augmented[pivotIndex]![columnIndex]) / pivot;
    }

    for (let rowIndex = 0; rowIndex < size; rowIndex += 1) {
      if (rowIndex === pivotIndex) continue;
      const factor = safeNumber(augmented[rowIndex]![pivotIndex]);
      if (factor === 0) continue;
      for (let columnIndex = 0; columnIndex < size * 2; columnIndex += 1) {
        augmented[rowIndex]![columnIndex] =
          safeNumber(augmented[rowIndex]![columnIndex]) - factor * safeNumber(augmented[pivotIndex]![columnIndex]);
      }
    }
  }

  return augmented.map((row) => row.slice(size));
}

export function assertFiniteWeights(weights: WeightVector, label: string): WeightVector {
  if (weights.featureNames.length !== weights.weights.length) {
    throw new Error(`[weight-learner] ${label} feature/weight length mismatch`);
  }
  if (!isFiniteNumber(weights.bias)) {
    throw new Error(`[weight-learner] ${label} bias is non-finite`);
  }
  if (!weights.weights.every((entry) => isFiniteNumber(entry))) {
    throw new Error(`[weight-learner] ${label} weights contain non-finite values`);
  }
  return weights;
}

function buildMetaFeatureVector(example: Omit<MetaTrainingExample, 'hit'>): number[] {
  return [
    Number(example.confidence) || 0,
    Number(example.confirmation) || 0,
    Number(example.reality) || 0,
    (Number(example.replayHitRate) || 0) / 100,
    (Number(example.currentHitRate) || 0) / 100,
    Number(example.coverage) || 0,
    Number(example.bandit) || 0,
    Number(example.transfer) || 0,
    Number(example.stability) || 0,
    Number(example.falsePositivePenalty) || 0,
    Number(example.driftPenalty) || 0,
  ];
}

function buildCredibilityFeatureVector(example: Omit<CredibilityTrainingExample, 'actualCredibility'>): number[] {
  return [
    Number(example.corroboration) || 0,
    Number(example.historicalAccuracy) || 0,
    Number(example.posteriorAccuracy) || 0,
    Number(example.truthAgreement) || 0,
    Number(example.emReliability) || 0,
    Number(example.feedHealth) || 0,
    Number(example.inversePropaganda) || 0,
  ];
}

function emptyWeights(featureNames: readonly string[]): WeightVector {
  return {
    featureNames: [...featureNames],
    weights: Array.from({ length: featureNames.length }, () => 0),
    bias: 0,
  };
}

export function trainMetaWeights(ideaRuns: MetaTrainingExample[]): MetaWeights {
  if (ideaRuns.length === 0) {
    return emptyWeights(META_FEATURE_NAMES) as MetaWeights;
  }

  const features = ideaRuns.map(({ hit: _hit, ...example }) => buildMetaFeatureVector(example));
  const targets = ideaRuns.map((example) => (example.hit ? 1 : 0));
  const featureCount = META_FEATURE_NAMES.length;
  const sampleCount = ideaRuns.length;
  const weights = Array.from({ length: featureCount }, () => 0);
  let bias = 0;

  for (let iteration = 0; iteration < META_ITERATIONS; iteration += 1) {
    const gradient = Array.from({ length: featureCount }, () => 0);
    let biasGradient = 0;

    for (let sampleIndex = 0; sampleIndex < sampleCount; sampleIndex += 1) {
      const row = features[sampleIndex]!;
      const prediction = sigmoid(dotProduct(weights, row) + bias);
      if (!Number.isFinite(prediction)) {
        throw new Error('[weight-learner] meta training produced a non-finite prediction');
      }
      const error = prediction - targets[sampleIndex]!;
      biasGradient += error;
      for (let featureIndex = 0; featureIndex < featureCount; featureIndex += 1) {
        const gradientValue = gradient[featureIndex] || 0;
        gradient[featureIndex] = gradientValue + (error * (row[featureIndex] || 0));
      }
    }

    for (let featureIndex = 0; featureIndex < featureCount; featureIndex += 1) {
      const gradientValue = gradient[featureIndex] || 0;
      const weightValue = weights[featureIndex] || 0;
      const regularizedGradient = (gradientValue / sampleCount) + (META_L2_LAMBDA * weightValue);
      if (!Number.isFinite(regularizedGradient)) {
        throw new Error('[weight-learner] meta training produced a non-finite gradient');
      }
      weights[featureIndex] = weightValue - (META_LEARNING_RATE * regularizedGradient);
    }
    bias -= META_LEARNING_RATE * (biasGradient / sampleCount);
    if (!Number.isFinite(bias)) {
      throw new Error('[weight-learner] meta training produced a non-finite bias');
    }
  }

  return assertFiniteWeights({
    featureNames: [...META_FEATURE_NAMES],
    weights,
    bias,
  }, 'meta model') as MetaWeights;
}

export function trainCredibilityWeights(sourceProfiles: CredibilityTrainingExample[]): CredibilityWeights {
  if (sourceProfiles.length === 0) {
    return emptyWeights(CREDIBILITY_FEATURE_NAMES) as CredibilityWeights;
  }

  const designMatrix = sourceProfiles.map(({ actualCredibility: _target, ...example }) => [
    1,
    ...buildCredibilityFeatureVector(example),
  ]);
  const targetVector = sourceProfiles.map((example) => Number(example.actualCredibility) || 0);
  const xt = transpose(designMatrix);
  const xtx = multiplyMatrices(xt, designMatrix);
  const regularized = xtx.map((row, rowIndex) =>
    row.map((value, columnIndex) => {
      if (rowIndex === 0 && columnIndex === 0) return value;
      if (rowIndex === columnIndex) return value + CREDIBILITY_L2_LAMBDA;
      return value;
    }));
  const xty = multiplyMatrixVector(xt, targetVector);
  const coefficients = multiplyMatrixVector(invertMatrix(regularized), xty);

  return assertFiniteWeights({
    featureNames: [...CREDIBILITY_FEATURE_NAMES],
    bias: safeNumber(coefficients[0]),
    weights: coefficients.slice(1).map((entry) => safeNumber(entry)),
  }, 'credibility model') as CredibilityWeights;
}

export function predictHitProbability(
  model: MetaWeights,
  features: Omit<MetaTrainingExample, 'hit'>,
): number {
  return sigmoid(dotProduct(model.weights, buildMetaFeatureVector(features)) + model.bias);
}

export function predictCredibility(
  model: CredibilityWeights,
  features: Omit<CredibilityTrainingExample, 'actualCredibility'>,
): number {
  const value = dotProduct(model.weights, buildCredibilityFeatureVector(features)) + model.bias;
  return Number.isFinite(value) ? value : 0;
}

export function isWeightVector(value: unknown): value is WeightVector {
  if (!value || typeof value !== 'object') return false;
  const candidate = value as Partial<WeightVector>;
  return Array.isArray(candidate.featureNames)
    && candidate.featureNames.every((entry) => typeof entry === 'string')
    && Array.isArray(candidate.weights)
    && candidate.weights.every((entry) => isFiniteNumber(entry))
    && isFiniteNumber(candidate.bias)
    && candidate.featureNames.length === candidate.weights.length;
}

/** Shared numeric helpers for adaptive-params modules. */

export function clamp(x: number, lo: number, hi: number): number {
  return Math.max(lo, Math.min(hi, x));
}

export function mean(arr: number[]): number {
  if (arr.length === 0) return 0;
  return arr.reduce((a, b) => a + b, 0) / arr.length;
}

export function std(arr: number[]): number {
  const m = mean(arr);
  return Math.sqrt(arr.reduce((s, x) => s + (x - m) ** 2, 0) / Math.max(1, arr.length - 1));
}

import type { MarketData } from '@/types';
import type { EventMarketTransmissionSnapshot } from '../../event-market-transmission';
import type { MacroRiskOverlay } from '../../macro-risk-overlay';
import type { KNNPrediction } from '../adaptive-params/embedding-knn.js';
import type { TransmissionProxy } from '../adaptive-params/transmission-proxy.js';
import type {
  IdeaGenerationRuntimeContext,
  MacroIndicatorSnapshot,
  ThemeAdmissionPolicy,
} from '../types';

function finiteOrNull(value: unknown): number | null {
  return typeof value === 'number' && Number.isFinite(value) ? value : null;
}

function clamp(value: number, minimum: number, maximum: number): number {
  if (!Number.isFinite(value)) return minimum;
  return Math.min(maximum, Math.max(minimum, value));
}

function average(values: number[]): number {
  if (values.length === 0) return 0;
  return values.reduce((sum, value) => sum + value, 0) / values.length;
}

function marketPriceBySymbol(markets: MarketData[]): Map<string, number> {
  const bySymbol = new Map<string, number>();
  for (const market of markets) {
    const symbol = String(market.symbol || '').trim().toUpperCase();
    const price = finiteOrNull(market.price);
    if (!symbol || price === null) continue;
    bySymbol.set(symbol, price);
  }
  return bySymbol;
}

export function deriveMacroIndicatorsFromMarkets(
  markets: MarketData[],
): MacroIndicatorSnapshot | null {
  const bySymbol = marketPriceBySymbol(markets);
  const indicators: MacroIndicatorSnapshot = {};

  const vix = bySymbol.get('^VIX') ?? bySymbol.get('VIX');
  const yieldSpread = bySymbol.get('T10Y2Y');
  const dollarIndex = bySymbol.get('DTWEXBGS') ?? bySymbol.get('DX-Y.NYB');
  const oilPrice = bySymbol.get('DCOILWTICO') ?? bySymbol.get('CL=F');

  if (vix != null) indicators.vix = vix;
  if (yieldSpread != null) indicators.yieldSpread = yieldSpread;
  if (dollarIndex != null) indicators.dollarIndex = dollarIndex;
  if (oilPrice != null) indicators.oilPrice = oilPrice;

  return Object.keys(indicators).length > 0 ? indicators : null;
}

function regimeStressFromLabel(label: string | null | undefined): number {
  const normalized = String(label || '').trim().toLowerCase();
  if (normalized === 'crisis') return 0.95;
  if (normalized === 'risk-off') return 0.78;
  if (normalized === 'balanced' || normalized === 'neutral') return 0.45;
  if (normalized === 'risk-on') return 0.18;
  return 0.32;
}

export function deriveTransmissionProxyFromSnapshot(args: {
  transmission: EventMarketTransmissionSnapshot | null;
  macroOverlay?: MacroRiskOverlay | null;
}): TransmissionProxy | null {
  const { transmission, macroOverlay } = args;
  if (!transmission) return null;

  const strengths = transmission.edges
    .map((edge) => finiteOrNull(edge.strength))
    .filter((value): value is number => value !== null)
    .map((value) => clamp(value / 100, 0, 1));
  const informationFlow = transmission.edges
    .map((edge) => finiteOrNull(edge.informationFlowScore))
    .filter((value): value is number => value !== null)
    .map((value) => clamp(value, 0, 1));
  const leadLag = transmission.edges
    .map((edge) => finiteOrNull(edge.leadLagScore))
    .filter((value): value is number => value !== null)
    .map((value) => clamp(value, 0, 1));

  const averageStrength = average(strengths);
  const peakStrength = strengths.length > 0 ? Math.max(...strengths) : 0;
  const regimeStress = regimeStressFromLabel(transmission.regime?.label);
  const regimeConfidence = clamp((Number(transmission.regime?.confidence) || 0) / 100, 0, 1);
  const overlayStress = macroOverlay
    ? clamp(
      macroOverlay.killSwitch
        ? 1
        : Math.max((Number(macroOverlay.riskGauge) || 0) / 100, regimeStress),
      0,
      1,
    )
    : regimeStress;

  const transmissionStrength = clamp(
    averageStrength * 0.65
    + peakStrength * 0.2
    + average(informationFlow) * 0.1
    + average(leadLag) * 0.05,
    0,
    1,
  );
  const marketStress = clamp(
    overlayStress * 0.55
    + transmissionStrength * 0.3
    + regimeConfidence * 0.15,
    0,
    1,
  );
  const reactionSignificance = clamp(
    average(informationFlow) * 0.55
    + average(leadLag) * 0.25
    + peakStrength * 0.2,
    0,
    1,
  );

  if (marketStress <= 0 && transmissionStrength <= 0 && reactionSignificance <= 0) {
    return null;
  }

  return {
    marketStress,
    transmissionStrength,
    reactionSignificance,
  };
}

export function buildIdeaGenerationRuntimeContext(args?: {
  markets?: MarketData[] | null;
  transmission?: EventMarketTransmissionSnapshot | null;
  macroOverlay?: MacroRiskOverlay | null;
  ragHitRate?: number | null;
  ragConfidence?: number | null;
  knnPrediction?: KNNPrediction | null;
  admissionThresholds?: ThemeAdmissionPolicy | null;
  ensembleModels?: unknown | null;
  mlNormalization?: { mean: number[]; std: number[] } | null;
  gdeltProxy?: TransmissionProxy | null;
  macroIndicators?: MacroIndicatorSnapshot | null;
}): IdeaGenerationRuntimeContext {
  const markets = Array.isArray(args?.markets) ? args.markets : [];
  const macroIndicators = args?.macroIndicators ?? deriveMacroIndicatorsFromMarkets(markets);
  const transmissionProxy = args?.gdeltProxy ?? deriveTransmissionProxyFromSnapshot({
    transmission: args?.transmission ?? null,
    macroOverlay: args?.macroOverlay ?? null,
  });

  return {
    rag: {
      hitRate: args?.ragHitRate ?? null,
      confidence: clamp(Number(args?.ragConfidence) || 0, 0, 1),
      knnPrediction: args?.knnPrediction ?? null,
    },
    admission: {
      thresholds: args?.admissionThresholds ?? null,
    },
    ml: {
      ensembleModels: args?.ensembleModels ?? null,
      normalization: args?.mlNormalization ?? null,
    },
    signal: {
      transmissionProxy,
      macroIndicators,
    },
  };
}
